/* =========================================================
Nombre completo: xlsx.min.js
Ruta o ubicación: /gestion-curricular-ccc/libs/xlsx.min.js
Función o funciones:
- Cargar la librería XLSX SheetJS para leer archivos Excel.
- Exponer window.XLSX para futuros parsers de PEA Base, PEA Unidades y PEA Actividades.
- Crear una promesa global window.__XLSXReady para esperar la carga correctamente.
- Usar CDN como solución rápida para pruebas en navegador.
- Permitir reemplazo futuro por el archivo oficial XLSX para modo offline/Electron.
========================================================= */

(function (window, document) {
  "use strict";

  var LIB_NAME = "XLSX";
  var READY_NAME = "__XLSXReady";

  var CDN_LIST = [
    "https://cdn.jsdelivr.net/npm/xlsx@0.18.5/dist/xlsx.full.min.js",
    "https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js",
    "https://unpkg.com/xlsx@0.18.5/dist/xlsx.full.min.js"
  ];

  var TIMEOUT_MS = 12000;

  if (window[LIB_NAME]) {
    window[READY_NAME] = Promise.resolve(window[LIB_NAME]);
    return;
  }

  if (window[READY_NAME]) {
    return;
  }

  function cargarScript(src) {
    return new Promise(function (resolve, reject) {
      var finalizado = false;
      var script = document.createElement("script");

      function terminarConError(error) {
        if (finalizado) return;
        finalizado = true;

        try {
          if (script && script.parentNode) {
            script.parentNode.removeChild(script);
          }
        } catch (e) {}

        reject(error);
      }

      function terminarOK() {
        if (finalizado) return;
        finalizado = true;
        resolve(window[LIB_NAME]);
      }

      script.src = src;
      script.async = false;
      script.defer = false;

      script.onload = function () {
        if (window[LIB_NAME]) {
          terminarOK();
        } else {
          terminarConError(
            new Error("El script XLSX cargó, pero window.XLSX no está disponible.")
          );
        }
      };

      script.onerror = function () {
        terminarConError(new Error("No se pudo cargar XLSX desde: " + src));
      };

      setTimeout(function () {
        if (!window[LIB_NAME]) {
          terminarConError(new Error("Tiempo agotado cargando XLSX desde: " + src));
        }
      }, TIMEOUT_MS);

      document.head.appendChild(script);
    });
  }

  async function cargarDesdeCDN() {
    var errores = [];

    for (var i = 0; i < CDN_LIST.length; i += 1) {
      try {
        await cargarScript(CDN_LIST[i]);

        if (window[LIB_NAME]) {
          return window[LIB_NAME];
        }
      } catch (error) {
        errores.push(error.message);
      }
    }

    throw new Error(
      "No se pudo cargar XLSX desde CDN. " +
      "Para trabajar offline en Electron, reemplaza /libs/xlsx.min.js por la librería oficial real. " +
      "Errores: " + errores.join(" | ")
    );
  }

  window[READY_NAME] = cargarDesdeCDN();
})(window, document);